此为HIT计算机网络Lab1内容 1. 设计并实现一个基本 HTTP 代理服务器。要求在指定端口（例如 8080）接收来自客户的 HTTP 请求并且根据其中的 URL 地址访问该地址所指向的 HTTP 服务器（原服务器），接收 HTTP 服务器的响应报文，并将响应报文转发给对应的客户进行浏览。 2. 设计并实现一个支持 Cache 功能的 HTTP 代理服务器。要求能缓存原服务器响应的对象，并能够通过修改请求报文（添加 if-modified-since头行），向原服务器确认缓存对象是否是最新版本。（选作内容，加分项目，可以当堂完成或课下完成） 3. 扩展 HTTP 代理服务器，支持如下功能：（选作内容，加分项目，可以当堂完成或课下完成） 4. 网站过滤：允许/不允许访问某些网站； 5. 用户过滤：支持/不支持某些用户访问外部网站； 6. 网站引导：将用户对某个网站的访问引导至一个模拟网站（钓鱼）。 [Toc] 实验原理和过程 创建套接字，绑定好端口和ip地址，并持续监听，直到接收到请求开始服务 接收请求头，对其进行解析，得到请求方法，请求主机，请求端口 检测是否为屏蔽网站(发送403 Forbidden)、屏蔽主机(发送403 Forbidden)、钓鱼目标网址(发送回钓鱼内容) 建立套接字和目标主机通信 检测是否存在cache、cache是否为最新 Cache最新，直接返回cache内容，无cache/cache需要更新，创建/更新cache，并发回给请求端 关闭除监听套接字以外的套接字 上述过程（2-7）循环 实验结果： 问题讨论 暂时不会实现https的cache功能 访问https网站会先发送一个connect请求，回复“HTTP/1.X 200 Connection Established

”后，由于https是加密通信，clinet_socket再发送过来的数据为加密数据，我暂时无法修改报文添加If Modified属性，应该是需要SSL知识 不知道为什么https代理加载速度非常快，而http代理加载速度很慢 心得体会 代理服务器本质功能是转发。 在http下，只需与目标建立连接，转发请求并且将获得的反馈发送给请求者即可； 而在https下，额外需要向请求方发送建立连接报文，再转发请求方的加密数据并且将获得的反馈发送给请求者。 对HTTP报文和运作方式了解加深了很多，能够改造报文实现某些功能。 源代码 # -*- coding:UTF-8 -*-&quot;&quot;&quot;author:LemontreeNdate:2021-10-27&quot;&quot;&quot;import _threadimport hashlibimport osimport socketimport timeimport requestsCACHE_DIR = os.path.join(os.path.dirname(__file__), &#x27;proxycache&#x27;)if not os.path.exists(CACHE_DIR): os.mkdir(CACHE_DIR)BLOCKED_WEB = [ &#x27;www.hit.edu.cn&#x27;,]BLOCKED_IP = [ # &#x27;127.0.0.1&#x27;,]FISHING_RULE = &#123; &#x27;today.hit.edu.cn&#x27;: &#x27;http://evaristexu.cc/&#x27;,&#125;class ProxyServer: def __init__(self): self.ip = &#x27;127.0.0.1&#x27; self.port = 7890 self.buffer_size = 4096 self.timeout = 60 @staticmethod def is_blocked_by_web(web): if web in BLOCKED_WEB: return True return False @staticmethod def is_blocked_by_ip(ip): if ip in BLOCKED_IP: return True return False def service(self, client_socket, client_ip): client_socket.settimeout(self.timeout) header = b&#x27;&#x27; while True: data = client_socket.recv(self.buffer_size) header = b&quot;%s%s&quot; % (header, data) if header.endswith(b&#x27;

&#x27;) or (not data): break if len(header) == 0: # 无数据报 client_socket.close() return request_decode = header.decode() print(&quot;header:&quot; + str(request_decode)) httpheader_firstline = request_decode.split(&quot;
&quot;)[0] print(&quot;fisrtline:&quot; + str(httpheader_firstline)) method = httpheader_firstline.split(&quot; &quot;)[0] url = httpheader_firstline.split(&quot; &quot;)[1] http_version = httpheader_firstline.split(&quot; &quot;)[2] # URL解析 http_pos = url.find(&quot;://&quot;) if http_pos == -1: temp = url else: temp = url[(http_pos + 3):] port_pos = temp.find(&quot;:&quot;) webserver_pos = temp.find(&quot;/&quot;) if webserver_pos == -1: webserver_pos = len(temp) if port_pos == -1 or webserver_pos &lt; port_pos: port = 80 webserver = temp[:webserver_pos] else: port = int(temp[(port_pos + 1):][:webserver_pos - port_pos - 1]) webserver = temp[:port_pos] print(&quot;TargetWebPage:&quot; + str(webserver)) print(&quot;Port:&quot; + str(port)) print(&quot;Method:&quot; + str(method)) print(&quot;HttpVersion:&quot; + str(http_version)) # 检测是否合法 # 1. 是否为屏蔽网站 if self.is_blocked_by_web(webserver): print(f&quot;&#123;webserver&#125;is forbidden
&quot;) client_socket.send(str.encode(&#x27;HTTP/1.1 403 Forbidden
&#x27;)) client_socket.close() return # 2. 是否为屏蔽IP if self.is_blocked_by_ip(client_ip[0]): print(f&quot;&#123;client_ip&#125;is forbidden
&quot;) client_socket.send(str.encode(&#x27;HTTP/1.1 403 Forbidden
&#x27;)) client_socket.close() return # 3. 根据字典跳转钓鱼网站 if webserver in FISHING_RULE: request = requests.get(url=str(FISHING_RULE.get(webserver))).content client_socket.sendall(request) client_socket.close() return m = hashlib.md5() m.update(str.encode(webserver)) # TODO; filename = os.path.join(CACHE_DIR, m.hexdigest() + &#x27;.ch&#x27;) server_socket = socket.socket(socket.AF_INET, socket.SOCK_STREAM) server_socket.settimeout(self.timeout) server_socket.connect((webserver, port)) # 有cache,检测是否为最新版本 if os.path.exists(filename) and method != &#x27;CONNECT&#x27;: temp = httpheader_firstline + &#x27;
&#x27; # 更新时间戳 t = (time.strptime(time.ctime(os.path.getmtime(filename)), &quot;%a %b %d %H:%M:%S %Y&quot;)) temp += &#x27;If-Modified-Since: &#x27; + time.strftime(&#x27;%a, %d %b %Y %H:%M:%S GMT&#x27;, t) + &#x27;
&#x27; for line in header.decode().split(&#x27;
&#x27;)[1:]: temp += line + &#x27;
&#x27; server_socket.sendall(str.encode(temp)) first = True while True: data = server_socket.recv(self.buffer_size) # 每次收取是按MAX_LENGTH获取,第一次创建cache文件 if first: print(&quot;REPLY:&quot; + str(data)) if data.decode(&#x27;iso-8859-1&#x27;).split()[1] == &#x27;304&#x27;: print(&#x27;Cache hit: &#123;path&#125;&#x27;.format(path=webserver)) # TODO; client_socket.send(open(filename, &#x27;rb&#x27;).read()) break else: o = open(filename, &#x27;wb&#x27;) print(&#x27;Cache updated: &#123;path&#125;&#x27;.format(path=webserver)) if len(data) &gt; 0: client_socket.send(data) o.write(data) else: break first = False else: o = open(filename, &#x27;ab&#x27;) if len(data) &gt; 0: client_socket.send(data) o.write(data) else: break # Cache不命中/HTTPS else: print(&#x27;Cache miss: &#123;path&#125;&#x27;.format(path=webserver)) if method == &#x27;CONNECT&#x27;: print(&quot;HTTPS!!!!&quot;) connect_back = http_version.encode()+b&quot; 200 Connection Established

&quot; client_socket.sendall(connect_back) _thread.start_new_thread(self.communicate, (client_socket, server_socket, filename, False)) else: print(&quot;HTTP!!!!&quot;) server_socket.send(header) self.communicate(server_socket, client_socket, filename, True) server_socket.close() client_socket.close() def communicate(self, socket1, socket2, filename, file): print(&quot;Start passing data&quot;) if file: o = open(filename, &#x27;ab&#x27;) while True: data = socket1.recv(self.buffer_size) if len(data) &gt; 0: o.write(data) socket2.send(data) else: break o.close() return else: while True: data = socket1.recv(self.buffer_size) if len(data) &gt; 0: socket2.send(data) else: break return def run(self): listen_socket = socket.socket(socket.AF_INET, socket.SOCK_STREAM) listen_socket.setsockopt(socket.SOL_SOCKET, socket.SO_REUSEADDR, 1) listen_socket.bind((self.ip, self.port)) listen_socket.listen(128) while True: print(&quot;---------waiting for a new clinet--------&quot;) client_socket, client_ip = listen_socket.accept() print(f&quot;开始响应来自&#123;client_ip&#125;的连接&quot;) _thread.start_new_thread(self.service, (client_socket, client_ip))if __name__ == &quot;__main__&quot;: proxy = ProxyServer() proxy.run()
